# - If you introduce any helper functions/classes, include their full implementations in this file; no hidden helpers.

class Solution(object):
    def minSizeSubarray(self, nums, target):
        """
        :type nums: List[int]
        :type target: int
        :rtype: int
        """
        n = len(nums)
        total_sum = sum(nums)
        
        if total_sum == target:
            return n
        if total_sum < target:
            return -1
        
        # Binary search for the minimum length
        left, right = 1, n
        while left < right:
            mid = (left + right) // 2
            if self.canAchieveTarget(nums, target, mid):
                right = mid
            else:
                left = mid + 1
        return left

    def canAchieveTarget(self, nums, target, length):
        current_sum = sum(nums[:length])
        if current_sum == target:
            return True
        for i in range(length, len(nums)):
            current_sum += nums[i] - nums[i - length]
            if current_sum == target:
                return True
        return False
        